#!/bin/bash\n# ICMS Local Development Launcher (Linux/Mac/Git Bash)\n# Usage: ./start-local.sh [--skip-frontend] [--skip-mongo] [--debug]\n\nset -e\n\n# Colors\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m' # No Color\n\necho \"\"\necho -e \"${BLUE}========================================${NC}\"\necho -e \"${BLUE}🚀 ICMS Local Development Setup${NC}\"\necho -e \"${BLUE}========================================${NC}\"\necho \"\"\n\n# Parse arguments\nSKIP_FRONTEND=false\nSKIP_MONGO=false\nDEBUG=false\n\nwhile [[ $# -gt 0 ]]; do\n    case $1 in\n        --skip-frontend) SKIP_FRONTEND=true; shift ;;\n        --skip-mongo) SKIP_MONGO=true; shift ;;\n        --debug) DEBUG=true; shift ;;\n        *) echo \"Unknown option: $1\"; exit 1 ;;\n    esac\ndone\n\n# Validation\necho -e \"${BLUE}[1/5]${NC} Validating prerequisites...\"\n\nif ! command -v rustc &> /dev/null; then\n    echo -e \"${RED}❌ Rust not found. Install from https://rustup.rs/${NC}\"\n    exit 1\nfi\necho -e \"${GREEN}✅ Rust: $(rustc --version)${NC}\"\n\nif ! command -v node &> /dev/null; then\n    echo -e \"${RED}❌ Node.js not found. Install from https://nodejs.org/${NC}\"\n    exit 1\nfi\necho -e \"${GREEN}✅ Node.js: $(node --version)${NC}\"\n\nif [ ! -f .env ]; then\n    echo -e \"${RED}❌ .env file not found${NC}\"\n    exit 1\nfi\necho -e \"${GREEN}✅ .env file found${NC}\"\necho \"\"\n\n# Frontend Build\nif [ \"$SKIP_FRONTEND\" = false ]; then\n    echo -e \"${BLUE}[2/5]${NC} Building React frontend...\"\n    \n    if [ ! -d frontend-TU ]; then\n        echo -e \"${RED}❌ frontend-TU directory not found${NC}\"\n        exit 1\n    fi\n    \n    cd frontend-TU\n    echo -e \"${BLUE}  Installing dependencies...${NC}\"\n    npm install --silent\n    \n    echo -e \"${BLUE}  Building for production...${NC}\"\n    npm run build --silent\n    \n    if [ ! -f dist/index.html ]; then\n        echo -e \"${RED}❌ Build failed: dist/index.html not found${NC}\"\n        exit 1\n    fi\n    \n    echo -e \"${GREEN}✅ Frontend built successfully${NC}\"\n    cd ..\n    echo \"\"\nelse\n    echo -e \"${BLUE}[2/5]${NC} Skipping frontend build (--skip-frontend)\"\n    echo \"\"\nfi\n\n# Environment\necho -e \"${BLUE}[3/5]${NC} Validating environment configuration...\"\n\nif grep -q \"MONGODB_URI\" .env; then\n    echo -e \"${GREEN}✅ MONGODB_URI configured${NC}\"\nelse\n    echo -e \"${RED}❌ MONGODB_URI not found in .env${NC}\"\n    exit 1\nfi\n\necho -e \"${GREEN}✅ Environment ready${NC}\"\necho \"\"\n\n# MongoDB Check\necho -e \"${BLUE}[4/5]${NC} Checking MongoDB...\"\n\nif [ \"$SKIP_MONGO\" = false ]; then\n    if command -v mongosh &> /dev/null; then\n        if mongosh --eval \"db.adminCommand('ping')\" mongodb://admin:admin123@localhost:27017/icms_db?authSource=admin &>/dev/null; then\n            echo -e \"${GREEN}✅ MongoDB is running and accessible${NC}\"\n        else\n            echo -e \"${YELLOW}⚠️  MongoDB not responding - start with: mongod${NC}\"\n        fi\n    else\n        echo -e \"${YELLOW}⚠️  MongoDB Shell not found - skipping connectivity check${NC}\"\n    fi\nelse\n    echo -e \"${YELLOW}⚠️  MongoDB check skipped (--skip-mongo)${NC}\"\nfi\necho \"\"\n\n# Backend Startup\necho -e \"${BLUE}[5/5]${NC} Starting Rust backend...\"\necho \"\"\necho -e \"${BLUE}========================================${NC}\"\n\ncd backend\n\nif [ \"$DEBUG\" = true ]; then\n    export RUST_LOG=debug\nelse\n    export RUST_LOG=info\nfi\n\necho -e \"${BLUE}Launching: cargo run${NC}\"\necho -e \"${BLUE}Press Ctrl+C to stop${NC}\"\necho \"\"\n\ncargo run\n